const app = express();

// --- Security middleware ---
app.disable('x-powered-by');
app.use(helmet());
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || [],
  methods: ['GET'],
}));
app.use(rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));
app.use(express.json({ limit: '10kb' }));
app.use(morgan('combined'));

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok' });
  // Removed timestamp to avoid server time disclosure
});

app.get('/users', authenticateToken, (req, res) => {
  // Return minimal data; real app would query DB with parameterized queries
  res.json([
    { name: 'Alice' },
    { name: 'Bob' },
  ]);
});

// --- Error handling ---
